// // This module toggles the output on each falling edge of the clock and resets to HIGH when reset is active.
module top_module(reset,clka,out);input reset; 
 input clka; 
 output out; 
 reg out; 
 always @(posedge clka or posedge reset) 
  if(reset) 
  out = 0; 
  else 
  out = ~out; 
 endmodule
